  padding: 16px;
}

.panel-header,
.actions {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 12px;
}

.mode-tabs {
  display: flex;
  gap: 8px;
  margin-bottom: 16px;
}

.mode-tab[data-active="true"] {
  background: #111827;
  color: #ffffff;
}

.mode-tab[data-active="false"] {
  background: #e5e7eb;
  color: #111827;
}

.field {
  display: grid;
  gap: 6px;
  min-width: 140px;
}

.field span,
.eyebrow {
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: #6b7280;
  margin: 0;
}

h1 {
  margin: 4px 0 0;
  font-size: 1.8rem;
}

.canvas-wrap {
  margin: 16px 0;
  border: 1px solid #d1d5db;
  border-radius: 12px;
  overflow: hidden;
  background: #fffef8;
}

#draw-canvas {
  display: block;
  width: 100%;
  height: min(60vh, 460px);
  touch-action: none;
  cursor: crosshair;
}

button {
  border: 0;
  border-radius: 10px;
  padding: 10px 16px;
  background: #111827;
  color: #ffffff;
  cursor: pointer;
}

.button-secondary {
  background: #e5e7eb;
  color: #111827;
}

input[type="file"],
select {
  width: 100%;
  border: 1px solid #d1d5db;
  border-radius: 10px;
  padding: 10px 12px;
  background: #ffffff;
}

.hint,
.status {
  color: #4b5563;
}

.file-name {
  margin: 12px 0;
  color: #374151;
}

.upload-preview-wrap {
  margin: 16px 0;
  min-height: 220px;
  display: grid;
  place-items: center;
  border: 1px solid #d1d5db;
  border-radius: 12px;
  background: #fffef8;
  overflow: hidden;
}

#upload-preview-image {
  display: block;
  max-width: 100%;
  max-height: 420px;
}

.panel-right {
  display: grid;
  align-content: start;
  gap: 16px;
}

.result-card {
  border: 1px solid #e5e7eb;
  border-radius: 12px;
  padding: 16px;
  background: #fafafa;
}

.result-text {
  min-height: 120px;
  padding: 12px;
  border-radius: 10px;
  background: #ffffff;
  border: 1px solid #e5e7eb;
  font-size: 1.5rem;
  white-space: pre-wrap;
}

.candidate-list {
  margin: 0;
  padding-left: 20px;
}

@media (max-width: 900px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .panel-header,
  .actions {
    align-items: start;
    flex-direction: column;
  }
}

