import { StrokeCanvas } from "./lib/stroke-canvas.js";
import { ResultView } from "./lib/result-view.js";
import { CameraMode } from "./modes/camera-mode.js";
import { DrawMode } from "./modes/draw-mode.js";
import { ModeSwitcher } from "./modes/mode-switcher.js";
import { UploadMode } from "./modes/upload-mode.js";
import { RecognitionApi } from "./services/recognition-api.js";

const strokeCanvas = new StrokeCanvas(document.querySelector("#draw-canvas"));
const recognitionApi = new RecognitionApi();
const resultView = new ResultView({
  resultText: document.querySelector("#result-text"),
  candidateList: document.querySelector("#candidate-list"),
  status: document.querySelector("#status")
});

const drawMode = new DrawMode({
  strokeCanvas,
  recognitionApi,
  languageSelect: document.querySelector("#language-select"),
  clearButton: document.querySelector("#clear-button"),
  resultView
});

const uploadMode = new UploadMode({
  recognitionApi,
  fileInput: document.querySelector("#image-file"),
  clearButton: document.querySelector("#upload-clear-button"),
  previewImage: document.querySelector("#upload-preview-image"),
  fileName: document.querySelector("#image-file-name"),
  resultView
});

const cameraMode = new CameraMode({
  recognitionApi,
  captureButton: document.querySelector("#camera-capture-button"),
  retakeButton: document.querySelector("#camera-retake-button"),
  video: document.querySelector("#camera-video"),
  previewImage: document.querySelector("#camera-preview-image"),
  resultView
});

const modeSwitcher = new ModeSwitcher({
  buttons: {
    draw: document.querySelector("#mode-draw-button"),
    upload: document.querySelector("#mode-upload-button"),
    camera: document.querySelector("#mode-camera-button")
  },
  panels: {
    draw: document.querySelector("#draw-panel"),
    upload: document.querySelector("#upload-panel"),
    camera: document.querySelector("#camera-panel")
  },
  title: document.querySelector("#mode-title"),
  hint: document.querySelector("#mode-hint"),
  alternativesCard: document.querySelector("#alternatives-card"),
  resultView,
  onModeChange: async (mode) => {
    cameraMode.leaveMode();

    if (mode === "draw") {
      strokeCanvas.resize();
    }

    if (mode === "camera") {
      await cameraMode.enterMode();
    }
  }
});

drawMode.mount();
uploadMode.mount();
cameraMode.mount();
modeSwitcher.mount();

export class ResultView {
  constructor({ resultText, candidateList, status }) {
    this.resultText = resultText;
    this.candidateList = candidateList;
    this.status = status;
  }

  setStatus(message) {
    this.status.textContent = message;
  }

  setResultText(text) {
    this.resultText.textContent = text;
  }

  setCandidates(candidates = []) {
    this.candidateList.innerHTML = "";

    if (!candidates.length) {
      const item = document.createElement("li");
      item.textContent = "No alternatives returned.";
      this.candidateList.append(item);
      return;
    }

    for (const candidate of candidates) {
      const item = document.createElement("li");
      item.textContent = candidate;
      this.candidateList.append(item);
    }
  }
}

:root {
  font-family: Arial, sans-serif;
  color: #111827;
  background: #f3f4f6;
  line-height: 1.4;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
}

button,
select,
input {
  font: inherit;
}

.app-shell {
  min-height: 100vh;
  display: grid;
  grid-template-columns: minmax(0, 1.2fr) minmax(320px, 0.8fr);
  gap: 16px;
  padding: 16px;
}

.panel {
  background: #ffffff;
  border: 1px solid #d1d5db;
  border-radius: 12px;
  padding: 16px;
}

.panel-header,
.actions {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 12px;
}

.mode-tabs {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 16px;
}

.mode-tab[data-active="true"] {
  background: #111827;
  color: #ffffff;
}

.mode-tab[data-active="false"] {
  background: #e5e7eb;
  color: #111827;
}

.field {
  display: grid;
  gap: 6px;
  min-width: 140px;
}

.field span,
.eyebrow {
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: #6b7280;
  margin: 0;
}

h1 {
  margin: 4px 0 0;
  font-size: 1.8rem;
}

.canvas-wrap {
  margin: 16px 0;
  border: 1px solid #d1d5db;
  border-radius: 12px;
  overflow: hidden;
  background: #fffef8;
}

#draw-canvas {
  display: block;
  width: 100%;
  height: min(60vh, 460px);
  touch-action: none;
  cursor: crosshair;
}

button {
  border: 0;
  border-radius: 10px;
  padding: 10px 16px;
  background: #111827;
  color: #ffffff;
  cursor: pointer;
}

.button-secondary {
  background: #e5e7eb;
  color: #111827;
}

input[type="file"],
select {
  width: 100%;
  border: 1px solid #d1d5db;
  border-radius: 10px;
  padding: 10px 12px;
  background: #ffffff;
}

.hint,
.status {
  color: #4b5563;
}

.file-name {
  margin: 12px 0;
  color: #374151;
}

.upload-preview-wrap {
.camera-stage {
  margin: 16px 0;
  min-height: 220px;
  display: grid;
  place-items: center;
  border: 1px solid #d1d5db;
  border-radius: 12px;
  background: #fffef8;
  overflow: hidden;
}

#upload-preview-image,
#camera-preview-image,
#camera-video {
  display: block;
  max-width: 100%;
  max-height: 420px;
}

#camera-video,
#camera-preview-image {
  width: 100%;
  background: #111827;
  aspect-ratio: 4 / 3;
  object-fit: cover;
}

.panel-right {
  display: grid;
  align-content: start;
  gap: 16px;
}

.result-card {
  border: 1px solid #e5e7eb;
  border-radius: 12px;
  padding: 16px;
  background: #fafafa;
}

.result-text {
  min-height: 120px;
  padding: 12px;
  border-radius: 10px;
  background: #ffffff;
  border: 1px solid #e5e7eb;
  font-size: 1.5rem;
  white-space: pre-wrap;
}

.candidate-list {
  margin: 0;
  padding-left: 20px;
}

@media (max-width: 900px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .panel-header,
  .actions {
    align-items: start;
    flex-direction: column;
  }
}

