+    const nextY = event.clientY - this.dragState.surfaceRect.top - this.dragState.offsetY;
+
+    artifact.x = Math.max(0, nextX);
+    artifact.y = Math.max(0, nextY);
+    this.render();
+  }
+
+  onPointerUp() {
+    this.dragState = null;
+  }
+
+  render() {
+    this.surface.innerHTML = "";
