  flex-direction: column;
  justify-content: center;
  padding: 0.9rem 1rem;
  box-shadow: 0 16px 28px rgba(24, 20, 12, 0.18);
  color: #2b2b25;
  cursor: grab;
  user-select: none;
  touch-action: none;
}

.shape-card.is-dragging {
  cursor: grabbing;
  box-shadow: 0 20px 34px rgba(24, 20, 12, 0.24);
}

.shape-card.is-resizing {
  cursor: nwse-resize;
  box-shadow: 0 20px 34px rgba(24, 20, 12, 0.24);
}

.shape-card.sticky,
.shape-card.circle,
.shape-card.heart {
  border: 1px solid rgba(115, 84, 44, 0.12);
}

.shape-card::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.22), transparent 28%);
  pointer-events: none;
}

.shape-card.sticky {
  width: 152px;
  min-height: 132px;
  background: #f2d89f;
  border-radius: 18px 24px 18px 20px;
  transform: rotate(-3deg);
}

.shape-card.circle {
  width: 144px;
  min-height: 144px;
  background: #d8e2d0;
  border-radius: 999px;
  transform: rotate(6deg);
  text-align: center;
}

