    18% 72%,
    7% 52%,
    9% 28%,
    23% 12%,
    36% 12%,
    50% 24%,
    64% 12%,
    77% 12%,
    91% 28%,
    93% 52%,
    82% 72%
  );
  transform: rotate(-5deg);
  padding: 2rem 1.25rem 1rem;
  text-align: center;
}

.shape-card.heart::before {
  clip-path: inherit;
}

.shape-card-title {
  position: relative;
  z-index: 1;
  font-family: 'Special Elite', serif;
  font-size: 0.74rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: rgba(64, 55, 41, 0.72);
  margin-bottom: 0.5rem;
}

.shape-card-text {
  position: relative;
  z-index: 1;
  font-family: 'IBM Plex Sans', sans-serif;
  font-size: 0.9rem;
  line-height: 1.35;
  overflow-wrap: anywhere;
}

.shape-resize-handle {
  position: absolute;
  right: 10px;
  bottom: 10px;
  width: 22px;
  height: 22px;
  border-radius: 999px;
  border: 2px solid rgba(64, 55, 41, 0.38);
  background:
    radial-gradient(circle at 35% 35%, rgba(255, 255, 255, 0.96), rgba(255, 255, 255, 0.5) 45%, rgba(64, 55, 41, 0.26) 100%);
  box-shadow: 0 6px 14px rgba(24, 20, 12, 0.28);
  cursor: nwse-resize;
  z-index: 2;
}

.shape-resize-handle::before,
.shape-resize-handle::after {
  content: '';
  position: absolute;
  background: rgba(64, 55, 41, 0.55);
  border-radius: 999px;
}

.shape-resize-handle::before {
  width: 10px;
  height: 2px;
  left: 5px;
  top: 10px;
  transform: rotate(45deg);
}

.shape-resize-handle::after {
  width: 10px;
  height: 2px;
  left: 8px;
  top: 7px;
  transform: rotate(45deg);
}

.shape-card.heart .shape-resize-handle {
  left: 50%;
  right: auto;
  bottom: 12px;
  transform: translateX(-50%);
}

.scrapbook-empty-tip {
  color: rgba(64, 55, 41, 0.6);
  font-size: 0.9rem;
  margin-top: 0.75rem;
  text-align: center;
}

