  gap: 1rem;
  align-items: flex-start;
  margin-bottom: 0.25rem;
}

.output-topline p {
  margin: 0.35rem 0 0;
  color: var(--muted);
  line-height: 1.5;
  max-width: 34ch;
}

.status {
  min-height: 1.4rem;
  color: rgba(247, 242, 232, 0.72);
  font-size: 0.9rem;
  max-width: 24ch;
}

.result-card {
  border: 1px solid rgba(255, 244, 224, 0.1);
  border-radius: 24px;
  padding: 1.2rem;
  background: rgba(8, 16, 21, 0.35);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.03);
}

.result-text {
  min-height: 220px;
  padding: 1.1rem;
  border-radius: 24px;
  background: rgba(8, 16, 21, 0.35);
  border: 1px solid rgba(255, 244, 224, 0.12);
  color: var(--text);
  font-size: 1.08rem;
  line-height: 1.6;
  white-space: pre-wrap;
}

.candidate-list {
  margin: 0;
  padding-left: 1.2rem;
  color: var(--muted);
}

.scrapbook-controls {
  display: grid;
  gap: 0.85rem;
  margin-top: 1rem;
}

.scrapbook-card {
  padding: 1.2rem;
  background:
    linear-gradient(135deg, rgba(247, 242, 232, 0.08), rgba(247, 242, 232, 0.02)),
    linear-gradient(180deg, rgba(5, 12, 15, 0.2), rgba(5, 12, 15, 0.5));
}

.scrapbook-toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.scrapbook-subtle {
  margin: 0;
  color: var(--muted);
}

.scrapbook-stage {
  position: relative;
  min-height: 780px;
  border-radius: 28px;
  padding: 1.25rem;
  overflow: hidden;
  background:
    linear-gradient(135deg, rgba(247, 242, 232, 0.08), rgba(247, 242, 232, 0.02)),
    linear-gradient(180deg, rgba(5, 12, 15, 0.2), rgba(5, 12, 15, 0.5));
  border: 1px solid rgba(255, 244, 224, 0.1);
}

.scrapbook-stage::before,
.scrapbook-stage::after {
  content: "";
  position: absolute;
  width: 180px;
  height: 180px;
  border-radius: 999px;
  filter: blur(10px);
  opacity: 0.35;
  pointer-events: none;
}

.scrapbook-stage::before {
  top: -40px;
  right: -30px;
  background: rgba(224, 179, 90, 0.12);
}

.scrapbook-stage::after {
  bottom: -55px;
  left: -45px;
  background: rgba(111, 143, 114, 0.12);
}

.scrapbook-meta {
  position: relative;
  z-index: 2;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.scrapbook-badge,
.scrapbook-date {
  padding: 0.45rem 0.75rem;
  border-radius: 999px;
