  position: absolute;
  inset: 0;
}

.scrapbook-background-layer {
  z-index: 1;
  pointer-events: none;
}

.scrapbook-artifacts-layer {
  z-index: 3;
}

.scrapbook-background-line {
  position: absolute;
  margin: 0;
  font-family: "Caveat", cursive;
  font-size: 1.65rem;
  line-height: 1;
  white-space: nowrap;
  color: #403729;
  opacity: 0.95;
  pointer-events: none;
}

.scrapbook-empty-state {
  position: absolute;
  inset: 24px;
  z-index: 4;
  margin: 0;
