  flex-direction: column;
  justify-content: center;
  padding: 0.9rem 1rem;
  color: #2b2b25;
  cursor: grab;
  user-select: none;
  touch-action: none;
  box-shadow: 0 16px 28px rgba(24, 20, 12, 0.18);
  overflow: hidden;
}

.scrapbook-artifact::before {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.22), transparent 28%);
  pointer-events: none;
}

.scrapbook-artifact:active {
  cursor: grabbing;
}

.scrapbook-artifact-label {
  position: relative;
  z-index: 1;
  margin: 0 0 0.5rem;
  font-family: "Special Elite", serif;
  font-size: 0.74rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: rgba(64, 55, 41, 0.72);
