:root {
  --bg-ink: #13262f;
  --bg-olive: #233d4d;
  --paper: #f5ecd9;
  --paper-deep: #e8d8b5;
  --accent-coral: #da6a53;
  --accent-gold: #e0b35a;
  --accent-leaf: #6f8f72;
  --panel: rgba(19, 38, 47, 0.78);
  --panel-edge: rgba(255, 244, 224, 0.16);
  --text: #f7f2e8;
  --muted: rgba(247, 242, 232, 0.72);
  --shadow: 0 24px 80px rgba(9, 20, 26, 0.32);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  padding: 2rem 1.25rem 2.5rem;
  font-family: "IBM Plex Sans", sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at top left, rgba(224, 179, 90, 0.12), transparent 30%),
    radial-gradient(circle at top right, rgba(218, 106, 83, 0.14), transparent 28%),
    linear-gradient(160deg, #102129 0%, #1a3340 50%, #14292f 100%);
}

button,
select,
input {
  font: inherit;
}

.app-shell {
  width: min(1260px, 100%);
  margin: 0 auto;
  display: grid;
  grid-template-columns: minmax(320px, 460px) minmax(360px, 1fr);
  gap: 1.5rem;
  align-items: start;
}

.panel {
  border-radius: 28px;
}

.workspace-panel {
  background: var(--panel);
  border: 1px solid var(--panel-edge);
  box-shadow: var(--shadow);
  backdrop-filter: blur(18px);
}

.input-workspace,
.output-workspace {
  padding: 1.5rem;
}

.panel-kicker {
  display: inline-flex;
  align-items: center;
  padding: 0.4rem 0.8rem;
  border-radius: 999px;
  background: rgba(224, 179, 90, 0.14);
  color: #ffe5a5;
  font-size: 0.8rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-bottom: 0.9rem;
}

.subtitle {
  margin: 0 0 1.5rem;
  color: var(--muted);
  line-height: 1.6;
  max-width: 44ch;
}

.mode-tabs {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.mode-tab[data-active="true"] {
  background: var(--accent-coral);
  border-color: var(--accent-coral);
  color: #fff8ef;
}

.mode-tab[data-active="false"] {
  background: rgba(13, 24, 31, 0.44);
  border-color: rgba(255, 244, 224, 0.14);
  color: var(--text);
}

.panel-header {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 1rem;
}

.eyebrow,
.field span {
  margin: 0;
  color: rgba(247, 242, 232, 0.58);
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

h1,
.output-topline h2,
.scrapbook-toolbar h2 {
  margin: 0.35rem 0 0;
  font-family: "Special Elite", serif;
}

h1 {
  font-size: clamp(2rem, 4vw, 3rem);
  line-height: 1.05;
}

.field {
  display: grid;
  gap: 0.4rem;
}

input[type="file"],
select {
  width: 100%;
  padding: 0.8rem 0.95rem;
  border-radius: 18px;
  border: 1px solid rgba(255, 244, 224, 0.14);
  background: rgba(8, 16, 21, 0.35);
  color: var(--text);
}

button {
  padding: 0.7rem 1.15rem;
  border: 1px solid rgba(255, 244, 224, 0.14);
  border-radius: 999px;
  background: rgba(13, 24, 31, 0.44);
  color: var(--text);
  cursor: pointer;
  font-size: 0.9rem;
  font-weight: 500;
  transition: all 0.2s ease;
}

button:hover {
  background: rgba(255, 244, 224, 0.12);
  border-color: rgba(255, 244, 224, 0.3);
  transform: translateY(-1px);
}

button:disabled {
  opacity: 0.45;
  cursor: not-allowed;
  transform: none;
}

.button-secondary {
  background: rgba(255, 244, 224, 0.08);
  color: var(--text);
}

#add-to-scrapbook-button,
#camera-capture-button {
  background: var(--accent-coral);
  border-color: var(--accent-coral);
  color: #fff8ef;
}

#add-to-scrapbook-button:hover,
#camera-capture-button:hover {
  background: #cb5a46;
}

.actions {
  display: flex;
  gap: 0.5rem;
  margin-top: 0.9rem;
  flex-wrap: wrap;
}

.hint {
  margin: 1rem 0 0;
  color: rgba(247, 242, 232, 0.48);
  font-size: 0.82rem;
}

.canvas-wrap {
  position: relative;
  margin: 1rem 0 0;
  background:
    linear-gradient(to bottom, rgba(58, 84, 116, 0.08) 0, rgba(58, 84, 116, 0.08) 1px, transparent 1px, transparent 34px),
    linear-gradient(to right, transparent 0, transparent 34px, rgba(220, 85, 84, 0.25) 34px, rgba(220, 85, 84, 0.25) 35px, transparent 35px),
    #fffdf7;
  background-size: 100% 35px, 100% 100%;
  border-radius: 24px;
  overflow: hidden;
  border: 1px solid rgba(255, 250, 240, 0.08);
}

#draw-canvas {
  display: block;
  width: 100%;
  height: min(60vh, 460px);
  touch-action: none;
  cursor: crosshair;
}

.file-name {
  margin: 0.8rem 0 0;
  color: var(--muted);
}

.upload-preview-wrap,
.camera-stage {
  display: grid;
  place-items: center;
  min-height: 220px;
  margin-top: 1rem;
  border-radius: 24px;
  overflow: hidden;
  background: rgba(8, 16, 21, 0.34);
  border: 1px dashed rgba(255, 244, 224, 0.18);
}

#upload-preview-image,
#camera-preview-image,
#camera-video {
  display: block;
  width: 100%;
  max-height: 340px;
  object-fit: contain;
  background: rgba(8, 16, 21, 0.35);
}

#camera-video,
#camera-preview-image {
  object-fit: cover;
  aspect-ratio: 4 / 3;
  background: rgba(8, 16, 21, 0.55);
}

.panel-right {
  min-height: 100%;
  display: grid;
  gap: 1rem;
}

.output-topline {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: flex-start;
  margin-bottom: 0.25rem;
}

.output-topline p {
  margin: 0.35rem 0 0;
  color: var(--muted);
  line-height: 1.5;
  max-width: 34ch;
}

.status {
  min-height: 1.4rem;
  color: rgba(247, 242, 232, 0.72);
  font-size: 0.9rem;
  max-width: 24ch;
}

.result-card {
  border: 1px solid rgba(255, 244, 224, 0.1);
  border-radius: 24px;
  padding: 1.2rem;
  background: rgba(8, 16, 21, 0.35);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.03);
}

.result-text {
  min-height: 220px;
  padding: 1.1rem;
  border-radius: 24px;
  background: rgba(8, 16, 21, 0.35);
  border: 1px solid rgba(255, 244, 224, 0.12);
  color: var(--text);
  font-size: 1.08rem;
  line-height: 1.6;
  white-space: pre-wrap;
}

.candidate-list {
  margin: 0;
  padding-left: 1.2rem;
  color: var(--muted);
}

.scrapbook-controls {
  display: grid;
  gap: 0.85rem;
  margin-top: 1rem;
}

.scrapbook-card {
  padding: 1.2rem;
  background:
    linear-gradient(135deg, rgba(247, 242, 232, 0.08), rgba(247, 242, 232, 0.02)),
    linear-gradient(180deg, rgba(5, 12, 15, 0.2), rgba(5, 12, 15, 0.5));
}

.scrapbook-toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.scrapbook-subtle {
  margin: 0;
  color: var(--muted);
}

.scrapbook-stage {
  position: relative;
  min-height: 780px;
  border-radius: 28px;
  padding: 1.25rem;
  overflow: hidden;
  background:
    linear-gradient(135deg, rgba(247, 242, 232, 0.08), rgba(247, 242, 232, 0.02)),
    linear-gradient(180deg, rgba(5, 12, 15, 0.2), rgba(5, 12, 15, 0.5));
  border: 1px solid rgba(255, 244, 224, 0.1);
}

.scrapbook-stage::before,
.scrapbook-stage::after {
  content: "";
  position: absolute;
  width: 180px;
  height: 180px;
  border-radius: 999px;
  filter: blur(10px);
  opacity: 0.35;
  pointer-events: none;
}

.scrapbook-stage::before {
  top: -40px;
  right: -30px;
  background: rgba(224, 179, 90, 0.12);
}

.scrapbook-stage::after {
  bottom: -55px;
  left: -45px;
  background: rgba(111, 143, 114, 0.12);
}

.scrapbook-meta {
  position: relative;
  z-index: 2;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.scrapbook-badge,
.scrapbook-date {
  padding: 0.45rem 0.75rem;
  border-radius: 999px;
  background: rgba(255, 248, 239, 0.15);
  border: 1px solid rgba(255, 248, 239, 0.18);
  color: #fff5de;
  font-size: 0.82rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.scrapbook-surface {
  position: relative;
  width: min(100%, 680px);
  min-height: 680px;
  margin: 0 auto;
  padding: 1.5rem;
  border-radius: 30px;
  background:
    linear-gradient(to bottom, rgba(58, 84, 116, 0.06) 0, rgba(58, 84, 116, 0.06) 1px, transparent 1px, transparent 35px),
    linear-gradient(to right, transparent 0, transparent 42px, rgba(220, 85, 84, 0.16) 42px, rgba(220, 85, 84, 0.16) 43px, transparent 43px),
    #f6eddb;
  background-size: 100% 35px, 100% 100%;
  box-shadow:
    0 24px 60px rgba(5, 12, 15, 0.36),
    inset 0 1px 0 rgba(255, 255, 255, 0.45);
  overflow: hidden;
}

.scrapbook-surface::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at top left, rgba(255, 255, 255, 0.35), transparent 26%),
    radial-gradient(circle at bottom right, rgba(203, 180, 134, 0.18), transparent 24%);
  pointer-events: none;
}

.scrapbook-background-layer,
.scrapbook-artifacts-layer {
  position: absolute;
  inset: 0;
}

.scrapbook-background-layer {
  z-index: 1;
  pointer-events: none;
}

.scrapbook-artifacts-layer {
  z-index: 3;
}

.scrapbook-background-line {
  position: absolute;
  margin: 0;
  color: #374151;
  font: 16px/24px Arial, sans-serif;
  white-space: pre-wrap;
}

.scrapbook-empty-state {
  position: absolute;
  inset: 24px;
  z-index: 4;
  margin: 0;
  display: grid;
