  padding: 0.9rem 1rem;
  color: #2b2b25;
  cursor: grab;
  user-select: none;
  touch-action: none;
  box-shadow: 0 16px 28px rgba(24, 20, 12, 0.18);
  overflow: hidden;
}

.scrapbook-artifact::before {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.22), transparent 28%);
  pointer-events: none;
}

.scrapbook-artifact:active {
  cursor: grabbing;
}

.scrapbook-artifact-label {
  position: relative;
  z-index: 1;
  margin: 0 0 0.5rem;
  font-family: "Special Elite", serif;
  font-size: 0.74rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: rgba(64, 55, 41, 0.72);
}

.scrapbook-artifact-text {
  position: relative;
  z-index: 1;
  margin: 0;
  font-size: 0.92rem;
  line-height: 1.35;
  white-space: pre-wrap;
  word-break: break-word;
}

.artifact-sticky {
  background: #f2d89f;
  border: 1px solid rgba(115, 84, 44, 0.12);
  border-radius: 18px 24px 18px 20px;
  transform: rotate(-3deg);
}

.artifact-circle {
  background: #d8e2d0;
  border: 1px solid rgba(115, 84, 44, 0.12);
  border-radius: 999px;
  transform: rotate(6deg);
  text-align: center;
}

.artifact-heart {
  background: #edc6bf;
  border: 1px solid rgba(115, 84, 44, 0.12);
  clip-path: polygon(
    50% 100%,
    18% 72%,
    7% 52%,
    9% 28%,
    23% 12%,
    36% 12%,
    50% 24%,
    64% 12%,
    77% 12%,
    91% 28%,
    93% 52%,
    82% 72%
  );
  transform: rotate(-5deg);
  text-align: center;
}

@media (max-width: 960px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .output-topline,
  .panel-header,
  .scrapbook-toolbar,
  .scrapbook-meta,
